        Box::new(
            get_all_processes()
                .into_iter()
                .map(|p| p.get_pid().to_string().into()),
        )
    }

    fn get_child(&self, name: &str) -> VfsResult<DynNodeOps> {
        let pid = name.parse::<Pid>().map_err(|_| VfsError::ENOENT)?;
        let builder = process_info_builder(self.fs.clone(), pid).ok_or(VfsError::ENOENT)?;
        Ok(builder.into())
    }
