impl<'a, I, E> ProcessResults<'a, I, E> {
    #[inline(always)]
    fn next_body<T>(&mut self, item: Option<Result<T, E>>) -> Option<T> {
        match item {
            Some(Ok(x)) => Some(x),
            Some(Err(e)) => {
                *self.error = Err(e);
                None
            }
            None => None,
        }
    }
}

